# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from flask import Flask, request, Response
from prometheus_client import Counter, generate_latest, CONTENT_TYPE_LATEST
import time

app = Flask(__name__)

request_counter = Counter(
    "http_requests_total",
    "Total HTTP requests",
    ["user_id", "session_id", "path"],
)

user_path_counters = {}

def get_user_path_counter(user_id, path):
    key = (user_id, path)
    if key not in user_path_counters:
        metric_name = f"http_requests_user_{sanitize_metric_part(user_id)}_path_{sanitize_metric_part(path)}_total"
        user_path_counters[key] = Counter(
            metric_name,
            f"HTTP requests for user {user_id} and path {path}",
        )
    return user_path_counters[key]

def sanitize_metric_part(value):
    sanitized = []
    for ch in str(value):
        if ch.isalnum():
            sanitized.append(ch.lower())
        else:
            sanitized.append("_")
    result = "".join(sanitized).strip("_")
    if not result:
        result = "unknown"
    if result[0].isdigit():
        result = f"v_{result}"
    return result

@app.before_request
def track_request():
    user_id = request.headers.get("X-User-Id", "anonymous")
    session_id = request.headers.get("X-Session-Id", "unknown")
    path = request.full_path.rstrip("?")
    request_counter.labels(user_id=user_id, session_id=session_id, path=path).inc()
    get_user_path_counter(user_id, path).inc()
    request.start_time = time.time()

@app.route("/")
def index():
    return {
        "message": "Hello, world!",
        "path": request.full_path.rstrip("?"),
    }

@app.route("/users/<user_id>")
def user_profile(user_id):
    return {
        "user_id": user_id,
        "path": request.full_path.rstrip("?"),
    }

@app.route("/metrics")
def metrics():
    return Response(generate_latest(), mimetype=CONTENT_TYPE_LATEST)

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=8000)